class Solution:
    def maxIncreasingGroups(self, usageLimits: List[int]) -> int:
        usageLimits.sort()
        res = 0
        total = 0
        for limit in usageLimits:
            total += limit
            if total >= (res + 1) * (res + 2) // 2:
                res += 1
        return res
